import React, { useState } from 'react'
import PaymentForm from './PaymentForm';
import {  Radio, Space } from 'antd';

const PaymentBody = ({setViewPage}:any) => {

  const [selectedValue, setSelectedValue] = useState(1);

  const handleChange = (value:any) => {
    setSelectedValue(value);
  };

  const RadioUi = ({value,children}:any)=>{
    return(
    <div>
      <Radio
      value={value}
      checked={selectedValue === value}
      onChange={() => handleChange(value)}
    >
      <span>Pay with credit card</span>
    </Radio>
    {selectedValue === value && <>{children}</>}
    </div>
    )
  }
  return (
    <div className="PaymentBody">
          <div className="PaymentBody_Left">
            <Space direction='vertical' >

   <RadioUi></RadioUi>
      <Radio
        value={2}
        checked={selectedValue === 2}
        onChange={() => handleChange(2)}
      >
        <span>Pay with Paypal</span>
      </Radio>
      {selectedValue === 2 && <div>hello</div>}

      <Radio
        value={3}
        checked={selectedValue === 3}
        onChange={() => handleChange(3)}
      >
        <span>Cash On Delivery</span>
      </Radio>
      {selectedValue === 3 && <div>hello</div>}   
      </Space>

           </div>
            <div className='PaymentBody_Right'>
             <PaymentForm/>
            </div>
    </div>
  )
}

export default PaymentBody
